headStyles:
body {
  background: var(--dark-bg);
}

.home-hero {
  padding: calc(var(--nav-height) + 2rem) 2rem 4rem;
  text-align: center;
  max-width: 900px;
  margin: 0 auto;
}

.home-hero {
  position: relative;
  overflow: hidden;
}
.home-hero::before {
  content: "";
  position: absolute;
  inset: 0;
  background: radial-gradient(circle at 20% 20%, rgba(255,255,255,0.08), transparent 35%),
    radial-gradient(circle at 80% 15%, rgba(163, 97, 255, 0.2), transparent 30%);
  pointer-events: none;
}
.home-hero > * {
  position: relative;
  z-index: 1;
}
.hero-badge {
  display: inline-block;
  margin-bottom: 1rem;
  padding: 0.35rem 0.8rem;
  font-family: "Montserrat", sans-serif;
  font-size: 0.8rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--text-white);
  border: 1px solid rgba(255, 255, 255, 0.35);
  border-radius: 999px;
  background: rgba(8, 21, 33, 0.55);
  box-shadow: 0 0 16px rgba(255, 255, 255, 0.15);
}
.nonpartisan-highlight {
  color: #b68cff;
  text-shadow: 0 0 12px rgba(182, 140, 255, 0.45);
}

.home-hero h1 {
  font-family: "Montserrat", sans-serif;
  font-size: clamp(2rem, 5vw, 3.5rem);
  line-height: 1.2;
  margin-bottom: 1.25rem;
  font-weight: 700;
  color: var(--text-white);
}
.home-hero .hero-subtitle {
  font-family: "Roboto Slab", serif;
  font-size: 1.1rem;
  color: var(--text-light);
  margin-bottom: 2rem;
  line-height: 1.7;
  max-width: 680px;
  margin-left: auto;
  margin-right: auto;
}
.home-hero .hero-divider {
  width: 80px;
  height: 4px;
  background: var(--pride-gradient);
  margin: 2rem auto;
  border-radius: 2px;
}
.home-hero .hero-buttons {
  display: flex;
  gap: 1.5rem;
  flex-wrap: wrap;
  justify-content: center;
  margin-top: 2rem;
}

.launch-day-callout {
  max-width: 900px;
  margin: 0 auto 1rem;
  padding: 0 2rem;
}
.launch-day-card {
  border: 1px solid rgba(182, 140, 255, 0.45);
  background: linear-gradient(135deg, rgba(19, 45, 68, 0.92), rgba(40, 18, 75, 0.82));
  border-radius: 14px;
  padding: 2rem;
  text-align: center;
  box-shadow: 0 0 24px rgba(118, 80, 180, 0.18);
}
.launch-day-card .section-label {
  margin-bottom: 0.75rem;
}
.launch-day-card h2 {
  font-family: "Montserrat", sans-serif;
  color: var(--text-white);
  margin-bottom: 0.75rem;
}
.launch-day-card p {
  font-family: "Roboto Slab", serif;
  color: var(--text-light);
  max-width: 640px;
  margin: 0 auto 1.5rem;
  line-height: 1.7;
}
.launch-day-meta {
  display: flex;
  justify-content: center;
  gap: 1rem;
  flex-wrap: wrap;
  margin-bottom: 1.5rem;
}
.launch-day-meta span {
  padding: 0.45rem 0.8rem;
  border-radius: 999px;
  background: rgba(255,255,255,0.08);
  color: var(--text-white);
  font-family: "Montserrat", sans-serif;
  font-size: 0.85rem;
}
.launch-day-actions {
  display: flex;
  gap: 1rem;
  justify-content: center;
  flex-wrap: wrap;
}

.launch-countdown {
  display: flex;
  justify-content: center;
  flex-wrap: wrap;
  gap: 0.6rem;
  margin: 0 auto 1.5rem;
  max-width: 640px;
}
.countdown-unit {
  flex: 1 1 0;
  min-width: 76px;
  padding: 1rem 0.6rem 0.85rem;
  border-radius: 12px;
  background: rgba(8, 21, 33, 0.75);
  border: 1px solid rgba(182, 140, 255, 0.35);
  box-shadow: 0 0 18px rgba(118, 80, 180, 0.12);
  position: relative;
  overflow: hidden;
  transition: transform 0.3s ease, box-shadow 0.3s ease;
}
.countdown-unit::after {
  content: "";
  position: absolute;
  left: 0;
  right: 0;
  bottom: 0;
  height: 3px;
  background: var(--pride-gradient);
  background-size: 200% 100%;
  opacity: 0.85;
  animation: countdownShimmer 6s linear infinite;
}
@keyframes countdownShimmer {
  0% { background-position: 0% 50%; }
  100% { background-position: 200% 50%; }
}
.countdown-unit-seconds {
  box-shadow: 0 0 22px rgba(255, 105, 180, 0.28);
}
.countdown-value {
  display: block;
  font-family: "Montserrat", sans-serif;
  font-weight: 700;
  font-size: clamp(1.75rem, 5vw, 2.5rem);
  line-height: 1;
  color: var(--text-white);
  background: var(--pride-gradient);
  background-size: 200% 100%;
  -webkit-background-clip: text;
  background-clip: text;
  -webkit-text-fill-color: transparent;
  letter-spacing: 0.02em;
  font-variant-numeric: tabular-nums;
  animation: countdownHue 8s linear infinite;
}
@keyframes countdownHue {
  0% { background-position: 0% 50%; }
  100% { background-position: 200% 50%; }
}
.countdown-label {
  display: block;
  margin-top: 0.4rem;
  font-family: "Montserrat", sans-serif;
  font-size: 0.72rem;
  font-weight: 600;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--text-light);
}
.countdown-tick {
  animation: countdownTick 0.55s ease-out;
}
.countdown-tick-fast {
  animation: countdownTickFast 0.45s ease-out;
}
@keyframes countdownTick {
  0% { transform: translateY(-8px) scale(1.05); opacity: 0.35; }
  60% { transform: translateY(2px) scale(1); opacity: 1; }
  100% { transform: translateY(0) scale(1); opacity: 1; }
}
@keyframes countdownTickFast {
  0% { transform: translateY(-4px) scale(1.12); opacity: 0.5; filter: drop-shadow(0 0 6px rgba(255, 150, 220, 0.7)); }
  100% { transform: translateY(0) scale(1); opacity: 1; filter: none; }
}
.countdown-pulse {
  animation: countdownPulse 1s ease-out;
}
@keyframes countdownPulse {
  0% { box-shadow: 0 0 22px rgba(255, 105, 180, 0.28); }
  40% { box-shadow: 0 0 34px rgba(118, 80, 180, 0.55); }
  100% { box-shadow: 0 0 22px rgba(255, 105, 180, 0.28); }
}
@media (prefers-reduced-motion: reduce) {
  .countdown-tick,
  .countdown-tick-fast,
  .countdown-pulse,
  .countdown-value,
  .countdown-unit::after { animation: none; }
}
@media (max-width: 480px) {
  .launch-countdown { gap: 0.4rem; }
  .countdown-unit { min-width: 0; padding: 0.7rem 0.3rem 0.55rem; }
  .countdown-value { font-size: clamp(1.4rem, 6vw, 2rem); }
  .countdown-label { font-size: 0.6rem; letter-spacing: 0.06em; }
}

.cards-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 2rem;
  margin-top: 2rem;
}
.wwd-card {
  border: 1px solid var(--dark-bg-light, #1a3a52);
  border-radius: 8px;
  padding: 2rem;
  background: rgba(19, 45, 68, 0.5);
  transition: all 0.3s ease;
  position: relative;
  overflow: hidden;
}
.wwd-card::before {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 3px;
  background: var(--pride-gradient);
  transform: scaleX(0);
  transition: transform 0.3s ease;
  transform-origin: left;
}
.wwd-card:hover::before {
  transform: scaleX(1);
}
.wwd-card:hover {
  border-color: var(--color-light-blue);
  transform: translateY(-4px);
}
.wwd-card .card-icon {
  font-size: 2rem;
  margin-bottom: 1rem;
}
.wwd-card h3 {
  font-family: "Montserrat", sans-serif;
  font-size: 1.2rem;
  margin-bottom: 0.75rem;
  color: var(--text-white);
}
.wwd-card p {
  font-family: "Roboto Slab", serif;
  color: var(--text-light);
  line-height: 1.7;
  font-size: 0.95rem;
}
.wwd-card .card-link {
  display: inline-block;
  margin-top: 1rem;
  color: var(--color-light-blue);
  font-size: 0.9rem;
  font-weight: 600;
  font-family: "Montserrat", sans-serif;
  text-decoration: none;
}
.wwd-card .card-link:hover {
  text-decoration: underline;
}
@media (max-width: 900px) {
  .cards-grid {
    grid-template-columns: 1fr;
  }
}

.founding-section {
  border-top: 3px solid;
  border-image: var(--pride-gradient) 1;
  padding-top: 4rem;
}
.founding-inner {
  max-width: 640px;
  margin: 0 auto;
  text-align: center;
}
.founding-desc {
  font-family: "Roboto Slab", serif;
  color: var(--text-light);
  line-height: 1.8;
  margin-bottom: 1.5rem;
  font-size: 1rem;
}
.stonewall-ref {
  font-family: "Roboto Slab", serif;
  font-size: 0.9rem;
  color: var(--text-light);
  font-style: italic;
  margin-bottom: 2rem;
  line-height: 1.6;
}
.founding-cta {
  text-align: center;
  margin-top: 2rem;
}

.scorecard-callout {
  max-width: 900px;
  margin: 0 auto 1rem;
  padding: 0 2rem;
}
.scorecard-card {
  border: 1px solid rgba(115, 215, 238, 0.35);
  background: linear-gradient(135deg, rgba(19, 45, 68, 0.92), rgba(12, 34, 55, 0.9));
  border-radius: 14px;
  padding: 2rem;
  box-shadow: 0 0 24px rgba(0, 77, 255, 0.12);
}
.scorecard-card .section-label { margin-bottom: 0.75rem; }
.scorecard-card h2 {
  font-family: "Montserrat", sans-serif;
  color: var(--text-white);
  margin-bottom: 0.75rem;
  text-align: center;
}
.scorecard-card > p {
  font-family: "Roboto Slab", serif;
  color: var(--text-light);
  max-width: 640px;
  margin: 0 auto 1.5rem;
  line-height: 1.7;
  text-align: center;
}
.scorecard-grades {
  display: grid;
  grid-template-columns: repeat(6, 1fr);
  gap: 0.5rem;
  margin: 0 auto 1.5rem;
  max-width: 520px;
}
.scorecard-grade {
  text-align: center;
  padding: 0.6rem 0.2rem;
  border-radius: 8px;
  background: rgba(255, 255, 255, 0.04);
  border: 1px solid rgba(255, 255, 255, 0.08);
}
.scorecard-grade .grade-letter {
  display: block;
  font-family: "Montserrat", sans-serif;
  font-weight: 800;
  font-size: 1.1rem;
  line-height: 1;
}
.scorecard-grade .grade-label {
  display: block;
  margin-top: 0.3rem;
  font-family: "Montserrat", sans-serif;
  font-size: 0.6rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--text-light);
}
.scorecard-actions {
  display: flex;
  gap: 1rem;
  justify-content: center;
  flex-wrap: wrap;
}
/* Keep labels on one line so grade cells stay visually balanced. */
.scorecard-grade .grade-label { white-space: nowrap; }

@media (max-width: 700px) {
  .scorecard-callout { padding: 0 1rem; }
  .scorecard-card { padding: 1.5rem 1.25rem; }
  /* 2 rows × 3 cells gives every label room to breathe instead of
     squeezing six cells into a viewport where "F" falls off the edge. */
  .scorecard-grades {
    grid-template-columns: repeat(3, 1fr);
    gap: 0.5rem;
    max-width: 360px;
  }
  .scorecard-grade { padding: 0.7rem 0.25rem; }
  .scorecard-grade .grade-letter { font-size: 1.05rem; }
  .scorecard-grade .grade-label { font-size: 0.6rem; letter-spacing: 0.06em; }
}
@media (max-width: 380px) {
  .scorecard-grades { gap: 0.35rem; }
  .scorecard-grade { padding: 0.55rem 0.2rem; }
  .scorecard-grade .grade-label { font-size: 0.55rem; letter-spacing: 0.04em; }
}

.donate-cta-card {
  background: rgba(19, 45, 68, 0.5);
  border: 1px solid var(--dark-bg-light, #1a3a52);
  border-radius: 8px;
  padding: 3rem 2rem;
  text-align: center;
  max-width: 600px;
  margin: 0 auto;
}
.donate-cta-card h2 {
  font-family: "Montserrat", sans-serif;
  color: var(--text-white);
  margin-bottom: 1rem;
}
.donate-cta-card p {
  font-family: "Roboto Slab", serif;
  color: var(--text-light);
  margin-bottom: 2rem;
}

@media (max-width: 768px) {
  .home-hero {
    padding: calc(var(--nav-height) + 1rem) 1.5rem 3rem;
  }
  .home-hero .hero-buttons {
    flex-direction: column;
    align-items: center;
  }
  .home-hero .hero-buttons .btn,
  .launch-day-actions .btn {
    width: 100%;
    max-width: 320px;
  }
  .launch-day-callout {
    padding: 0 1.5rem;
  }
}

