(function () {
  var root = document.getElementById("launchCountdown");
  if (!root) return;
  var target = new Date(root.getAttribute("data-target")).getTime();
  if (isNaN(target)) return;

  var daysEl = document.getElementById("cdDays");
  var hoursEl = document.getElementById("cdHours");
  var minutesEl = document.getElementById("cdMinutes");
  var secondsEl = document.getElementById("cdSeconds");
  var secondsUnit = secondsEl ? secondsEl.parentNode : null;

  function pad(n) { n = Math.max(0, n); return n < 10 ? "0" + n : "" + n; }

  function setValue(el, next, tickClass) {
    if (!el) return;
    if (el.textContent === next) return;
    el.textContent = next;
    var cls = tickClass || "countdown-tick";
    el.classList.remove("countdown-tick", "countdown-tick-fast");
    void el.offsetWidth;
    el.classList.add(cls);
  }

  function pulseUnit(unit) {
    if (!unit) return;
    unit.classList.remove("countdown-pulse");
    void unit.offsetWidth;
    unit.classList.add("countdown-pulse");
  }

  function render() {
    var diff = target - Date.now();
    if (diff <= 0) {
      setValue(daysEl, "0");
      setValue(hoursEl, "00");
      setValue(minutesEl, "00");
      setValue(secondsEl, "00");
      return false;
    }
    var totalSeconds = Math.floor(diff / 1000);
    var days = Math.floor(totalSeconds / 86400);
    var hours = Math.floor((totalSeconds % 86400) / 3600);
    var minutes = Math.floor((totalSeconds % 3600) / 60);
    var seconds = totalSeconds % 60;
    setValue(daysEl, String(days));
    setValue(hoursEl, pad(hours));
    setValue(minutesEl, pad(minutes));
    var prevSeconds = secondsEl ? secondsEl.textContent : "";
    setValue(secondsEl, pad(seconds), "countdown-tick-fast");
    if (seconds === 0 && prevSeconds !== "00" && prevSeconds !== "") {
      pulseUnit(secondsUnit);
    }
    return true;
  }

  render();
  var msToNextSecond = 1000 - (Date.now() % 1000);
  setTimeout(function tick() {
    if (render()) setTimeout(tick, 1000 - (Date.now() % 1000));
  }, msToNextSecond);
})();
